namespace sv_193eee7cfe29456ea7d290f605fc5779.Models;

public sealed class Recipe
{
    public required int Id { get; init; }
    public required string Title { get; init; }
    public required string Description { get; init; }
    public required int PrepTimeMinutes { get; init; }
}

using sv_193eee7cfe29456ea7d290f605fc5779.Models;

namespace sv_193eee7cfe29456ea7d290f605fc5779.Services;

public interface IRecipeService
{
    Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken);
}

public sealed class RecipeService : IRecipeService
{
    private static readonly Dictionary<int, List<Recipe>> RecipesByCuisine = new()
    {
        [1] = new List<Recipe>
        {
            new() { Id = 1, Title = "Margherita Pizza", Description = "Classic Neapolitan pizza with fresh mozzarella, San Marzano tomatoes, and basil.", PrepTimeMinutes = 30 },
            new() { Id = 2, Title = "Spaghetti Carbonara", Description = "Roman pasta with guanciale, egg yolks, Pecorino Romano, and black pepper.", PrepTimeMinutes = 25 },
            new() { Id = 3, Title = "Risotto alla Milanese", Description = "Creamy Arborio rice infused with saffron and finished with Parmigiano-Reggiano.", PrepTimeMinutes = 45 },
        },
        [2] = new List<Recipe>
        {
            new() { Id = 4, Title = "Chicken Tikka Masala", Description = "Tender chicken pieces in a rich, spiced tomato-cream sauce.", PrepTimeMinutes = 50 },
            new() { Id = 5, Title = "Palak Paneer", Description = "Cubes of fresh paneer in a smooth, spiced spinach gravy.", PrepTimeMinutes = 35 },
            new() { Id = 6, Title = "Biryani", Description = "Fragrant basmati rice layered with marinated meat, saffron, and caramelized onions.", PrepTimeMinutes = 60 },
        },
        [3] = new List<Recipe>
        {
            new() { Id = 7, Title = "Tacos al Pastor", Description = "Spit-grilled pork with pineapple, cilantro, and onion on corn tortillas.", PrepTimeMinutes = 40 },
            new() { Id = 8, Title = "Guacamole", Description = "Ripe avocados mashed with lime juice, cilantro, jalapeño, and tomato.", PrepTimeMinutes = 10 },
            new() { Id = 9, Title = "Enchiladas Verdes", Description = "Corn tortillas filled with chicken and smothered in tangy tomatillo salsa verde.", PrepTimeMinutes = 45 },
        },
    };

    public async Task<List<Recipe>> GetByCuisineAsync(int cuisineId, CancellationToken cancellationToken)
    {
        // Simulate a slow API call.
        await Task.Delay(2000, cancellationToken);

        if (RecipesByCuisine.TryGetValue(cuisineId, out var recipes))
        {
            return recipes;
        }

        return new List<Recipe>();
    }
}

