@page "/recipes/{CuisineId:int}"
@using sv_193eee7cfe29456ea7d290f605fc5779.Models
@using sv_193eee7cfe29456ea7d290f605fc5779.Services
@rendermode InteractiveServer
@implements IAsyncDisposable
@inject IRecipeService RecipeService
@inject ILogger<Recipes> Logger

<PageTitle>Recipes</PageTitle>

<h1>Recipes</h1>

@if (errorMessage is not null)
{
    <div class="alert alert-danger d-flex justify-content-between align-items-center" role="alert">
        <span>@errorMessage</span>
        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
    </div>
}

@if (recipes is null && errorMessage is null)
{
    <p><em>Loading recipes...</em></p>
}
else if (recipes is not null)
{
