+                <tr>
+                    <th>Title</th>
+                    <th>Description</th>
+                    <th>Prep Time (min)</th>
+                </tr>
+            </thead>
+            <tbody>
+                @foreach (var recipe in displayedRecipes)
+                {
+                    <tr>
+                        <td>@recipe.Title</td>
