+
+@code {
+    [Parameter]
+    public int CuisineId { get; set; }
+
+    [SupplyParameterFromQuery(Name = "sort")]
+    public string? Sort { get; set; }
+
+    private List<Recipe>? recipes;
+    private string? errorMessage;
+    private bool isRefreshing;
+    private int loadedCuisineId;
+
+    private CancellationTokenSource? loadCts;
+    private readonly CancellationTokenSource disposalCts = new();
+
+    private IReadOnlyList<Recipe> displayedRecipes =>
+        recipes is null
+            ? Array.Empty<Recipe>()
+            : string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
+                ? recipes.OrderByDescending(r => r.PrepTimeMinutes).ToList()
+                : recipes.OrderByDescending(r => r.Id).ToList();
+
+    protected override async Task OnParametersSetAsync()
+    {
+        if (CuisineId == loadedCuisineId && recipes is not null)
+        {
+            // Only the sort parameter (or nothing) changed — no reload needed.
+            return;
+        }
+
+        await LoadRecipesAsync();
+    }
+
+    private async Task LoadRecipesAsync()
+    {
+        // Cancel any in-flight load for a previous cuisine.
+        if (loadCts is not null)
+        {
+            await loadCts.CancelAsync();
+            loadCts.Dispose();
+        }
+
+        loadCts = CancellationTokenSource.CreateLinkedTokenSource(disposalCts.Token);
+
+        isRefreshing = recipes is not null;
+        errorMessage = null;
+
+        try
+        {
+            var results = await RecipeService.GetByCuisineAsync(CuisineId, loadCts.Token);
+
+            recipes = results;
+            loadedCuisineId = CuisineId;
+            isRefreshing = false;
+        }
+        catch (OperationCanceledException) when (disposalCts.IsCancellationRequested)
+        {
+            // Component is being disposed — stop all work silently.
+        }
+        catch (OperationCanceledException)
+        {
+            // A newer cuisine load superseded this one — nothing to do.
+        }
+        catch (TimeoutException ex)
+        {
+            Logger.LogError(ex, "Timeout loading recipes for cuisine {CuisineId}", CuisineId);
+            errorMessage = "The request timed out. Please try again.";
+            isRefreshing = false;
+        }
+        catch (Exception ex)
+        {
+            Logger.LogError(ex, "Error loading recipes for cuisine {CuisineId}", CuisineId);
+            errorMessage = "Something went wrong while loading recipes. Please try again.";
+            isRefreshing = false;
+        }
+    }
+
+    private async Task RetryAsync()
+    {
+        await LoadRecipesAsync();
+    }
+
+    public async ValueTask DisposeAsync()
+    {
+        await disposalCts.CancelAsync();
+
+        if (loadCts is not null)
+        {
+            loadCts.Dispose();
+        }
+
+        disposalCts.Dispose();
+    }
+}
